import re, pathlib
p = pathlib.Path('/Users/gbang/Downloads/algora/workspace/ec6fef8d-7160-482a-8357-612b13ca5360_hld/_response.md')
md = p.read_text()
blocks = re.findall(r'```mermaid\n(.*?)```', md, re.S)
print("blocks:", len(blocks))
# Breaking chars to check INSIDE node labels [..] {..} {{..}} [(..)] and edge labels |".."|
bad = ['(',')','[',']',':','/','"','<','>',';']
for i, b in enumerate(blocks, 1):
    issues = []
    # extract bracket label contents and pipe-edge labels
    # node labels: [..], [(..)], {{..}}, {..}
    for m in re.finditer(r'\[\(([^\)\]]*)\)\]', b):  # cylinder [(..)]
        lbl = m.group(1)
        for c in bad:
            if c in lbl: issues.append(f"cyl[({lbl})] has '{c}'")
    for m in re.finditer(r'\{\{([^}]*)\}\}', b):  # hex {{..}}
        lbl = m.group(1)
        for c in bad:
            if c in lbl: issues.append(f"hex{{{{{lbl}}}}} has '{c}'")
    # plain [..] not preceded by ( -- approximate
    for m in re.finditer(r'(?<!\()\[([^\[\]\(\)]*)\]', b):
        lbl = m.group(1)
        for c in bad:
            if c in lbl: issues.append(f"box[{lbl}] has '{c}'")
    # decision {..} single
    for m in re.finditer(r'(?<!\{)\{([^{}]*)\}(?!\})', b):
        lbl = m.group(1)
        for c in bad:
            if c in lbl: issues.append(f"dia{{{lbl}}} has '{c}'")
    # edge labels |".."|
    for m in re.finditer(r'\|"([^"]*)"\|', b):
        lbl = m.group(1)
        for c in bad:
            if c in lbl: issues.append(f"edge|{lbl}| has '{c}'")
    print(f"--- block {i}: {'OK' if not issues else 'ISSUES'}")
    for x in issues: print("   ", x)
